// Agent 3 â€” Restructuring Brief
// Input: compte Google Ads structurÃ©
// {
//   account_name: string,
//   monthly_budget: number,
//   campaigns: [
//     {
//       name: string,
//       type: string,           // Search / Shopping / PMax / Display
//       status: string,         // enabled / paused
//       budget_daily: number,
//       spend_30d: number,
//       conversions_30d: number,
//       cpa_30d: number,
//       roas_30d: number,       // optionnel
//       impression_share: number, // 0-1
//       quality_score_avg: number, // 1-10
//       ad_groups_count: number,
//       keywords_count: number,
//       top_issues: string[]    // ex: ['faible QS', 'chevauchement keywords']
//     }
//   ],
//   objectives: string,         // ex: 'reduire CPL de 20% en 3 mois'
//   industry: string,           // ex: 'SaaS B2B', 'e-commerce mode'
//   target_cpa: number          // optionnel
// }

const body = $input.first().json.body ?? $input.first().json;

if (!body.campaigns || !Array.isArray(body.campaigns) || body.campaigns.length === 0) {
  throw new Error('Body requis : { campaigns: [...], account_name, monthly_budget, objectives, industry }');
}

// Formatter les campagnes en tableau lisible pour Claude
const campRows = body.campaigns.map(c => {
  return [
    `Campagne: ${c.name}`,
    `  Type: ${c.type || 'N/A'} | Statut: ${c.status || 'N/A'}`,
    `  Budget/jour: ${c.budget_daily ? c.budget_daily + ' EUR' : 'N/A'} | Spend 30j: ${c.spend_30d ? c.spend_30d + ' EUR' : 'N/A'}`,
    `  Conversions 30j: ${c.conversions_30d ?? 'N/A'} | CPA 30j: ${c.cpa_30d ? c.cpa_30d + ' EUR' : 'N/A'} | ROAS: ${c.roas_30d ?? 'N/A'}`,
    `  IS: ${c.impression_share ? (c.impression_share * 100).toFixed(0) + '%' : 'N/A'} | QS moyen: ${c.quality_score_avg ?? 'N/A'}/10`,
    `  Groupes: ${c.ad_groups_count ?? 'N/A'} | Keywords: ${c.keywords_count ?? 'N/A'}`,
    c.top_issues && c.top_issues.length > 0 ? `  Problemes: ${c.top_issues.join(', ')}` : ''
  ].filter(Boolean).join('\n');
}).join('\n\n');

const context = [
  `Compte : ${body.account_name || 'Non specifie'}`,
  `Budget mensuel : ${body.monthly_budget ? body.monthly_budget + ' EUR' : 'Non specifie'}`,
  `Secteur : ${body.industry || 'Non specifie'}`,
  `Objectif : ${body.objectives || 'Non specifie'}`,
  body.target_cpa ? `CPA cible : ${body.target_cpa} EUR` : ''
].filter(Boolean).join('\n');

const userMsg = `CONTEXTE DU COMPTE :\n${context}\n\nCAMPAGNES :\n${campRows}\n\nGENERE UN BRIEF DE RESTRUCTURATION GOOGLE ADS complet.`;

return [{ json: { userMsg, accountName: body.account_name || 'Compte', campaignCount: body.campaigns.length } }];

// Formatter la rÃ©ponse Claude en brief structurÃ©
const item = $input.first();
const claudeResp = item.json;

const text = claudeResp.content && claudeResp.content[0] ? claudeResp.content[0].text : JSON.stringify(claudeResp);

// Metadata de l'appel
const usage = claudeResp.usage || {};

return [{
  json: {
    brief: text,
    model: claudeResp.model || 'claude-sonnet-4-6',
    tokens_used: (usage.input_tokens || 0) + (usage.output_tokens || 0),
    generated_at: new Date().toISOString()
  }
}];
